INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00127', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對於受刑人送入之金錢、飲食及必需物品之規定，下列敘述何者錯誤？', '["機關應於平日指定時間、地點辦理外界送入予收容人之財物。國定例假日或其他休息日，得由機關 斟酌情形辦理之", "監獄對於外界送入之金錢、飲食、必需物品及其他財物，所實施之檢查不得逾必要之程度", "外界送入金錢，每一送入人對個別收容人每日限一次，每次以新臺幣一萬元為限。但經機關長官許 可者，不在此限", "外界送入飲食，受刑人每二日一次，每次不得逾三公斤。但經機關長官許可者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00128', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及相關法規規定，得給予受刑人奬勵之方式，下列敘述何者錯誤？', '["增給成績分數：增加當月成績總分一分至六分", "增加接見或通信次數：合併或個別增加一次至三次", "給與相當數額之獎金：一般性獎金，每人每次最高額以新臺幣六千元為限。參加比賽之獎金，依相 關比賽規定給與之", "其他特別獎勵：得給予與眷屬同住或返家探親之獎勵，於受刑人另案經禁止接見通信者，不適用之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00129', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄辦理接見日期、次數及時間的規定，下列敘述何者正確？', '["監獄應於平日辦理接見；國定例假日或其他休息日之接見，得由監獄斟酌情形辦理之", "受刑人之接見，除法規另有規定外，每星期二次，接見時間以二十分鐘為限", "第四級受刑人每星期一次或二次", "第三級受刑人每三日一次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00130', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第55條第2項規定，受刑人或其最近親屬及家屬，在不妨礙監獄秩序及經醫師評估有必 要之情形下，得請求監獄核准下列那一種方式進行健康檢查？', '["保外就醫", "自費延醫", "移送病監", "戒護外醫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00131', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法對於受刑人之申訴、訴訟各項時效規定，下列敘述何者錯誤？', '["審議小組認為申訴書不合法定程式，而其情形可補正者，應通知申訴人於五日內補正", "審議小組應自受理申訴之次日起三十日內作成決定，必要時得延長十日，並通知申訴人", "訴訟之提起，應於申訴決定書送達後三十日之不變期間內為之", "本法第93條第1款處分或管理措施、第2款、第3款拒絕請求之申訴，應自受刑人收受或知悉處 分或管理措施之次日起，十五日不變期間內為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00132', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第69條，有關請求接見受刑人之規定，下列敘述何者錯誤？', '["請求接見者，應繳驗身分證明文件，登記其姓名、職業、年齡、住居所、受刑人姓名與受刑人之關係", "監獄對於請求接見者認為有妨害監獄秩序、安全或利益時，應拒絕之", "接見應於接見室為之。但因患病或於管理教化上之必要，得准於適當處所行之", "接見每次不得逾三人。但本法或其他法規另有規定，或經監獄長官許可者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00133', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及相關法規規定，有關受刑人之提報假釋之法定要件，下列敘述何者錯誤？', '["刑法第77條：受徒刑之執行而有悛悔實據者，無期徒刑逾二十五年，有期徒刑逾二分之一、累犯 逾三分之二，由監獄報請法務部，得許假釋出獄", "少年事件處理法第81條：少年受徒刑之執行而有悛悔實據者，無期徒刑逾七年後，有期徒刑逾執 行期三分之一後，得予假釋", "行刑累進處遇條例第76條：二級受刑人已適於社會生活，而合於法定假釋之規定者，得報請假釋", "行刑累進處遇條例施行細則第57條：一般受刑人最近三個月內教化、作業、操行各項分數，均應在 三分以上，少年受刑人最近三個月內教化分數應在二分以上，操行分數在三分以上，作業分數應在四 分以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00134', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及相關法規規定，監獄應設假釋審查會，有關其組成及運作相關事項，下列敘述何者錯 誤？', '["置委員七人至十一人，除典獄長及其指派監獄代表二人為當然委員外，其餘委員由各監獄遴選具有 心理、教育、法律、犯罪、監獄學、觀護、社會工作或相關專門學識之人士，報請監督機關核准後 聘任之", "假釋審查會須有全體委員過半數出席，始得開會。但本法第120條第1項有關維持或廢止假釋之案 件，應有二分之一之委員出席", "假釋審查會每月至少舉行一次。必要時，得增加次數", "假釋審查之決議採無記名投票方式，由出席委員過半數同意行之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00135', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對於受刑人攜帶、在監取得或外界送入之金錢與物品，有明文規定處置之方式，下列敘述何者錯誤？', '["經檢查後，由監獄代為保管", "監獄認有必要且無妨害監獄秩序或安全之虞者，得准許其在監使用", "監獄不得依受刑人之請求，予以毀棄", "代管之金錢，除酌留一定金額作為週轉金外，應設專戶管理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00136', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人獲得與眷同住之獎勵，根據受刑人獎勵實施辦法，下列敘述何者錯誤？', '["受刑人累進處遇進至三級以上，有期徒刑執行逾二分之一，無期徒刑執行逾十五年，且最近一年無 懲罰紀錄", "受刑人刑期未滿一年、拘役或易服勞役執行期間無懲罰紀錄", "經報請監督機關備查後，於監獄之指定處所及期間，使受刑人與眷屬生活或相處", "與眷屬同住，每次以三日為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
